// Package checksums owns forge's file-ownership machinery: which bytes
// does forge certify as its own render, which files has the user taken
// over, and what may a generate run overwrite.
//
// ── The mechanism (2026-06 redesign) ──────────────────────────────────
//
// Tier-1 (regenerated-every-run) files are SELF-CERTIFYING: each one
// embeds its own content hash in the "Code generated by forge. DO NOT
// EDIT." header (`forge:hash=<sha256>` — see stamp.go for the hash
// spec and comment-syntax matrix). The pristine check is purely local:
// recompute vs embedded. There is no global manifest for Tier-1 — the
// old .forge/checksums.json was shared mutable state OUTSIDE the files
// it described, and it produced the fr-9a54388f0b failure class: a
// manifest committed from a WIP lane made a clean clone of green HEAD
// unable to regenerate itself, and every regen rewrote the manifest
// (pure-bookkeeping commits, constant conflicts between parallel
// agents).
//
// Verification outcomes at a Tier-1 write site:
//
//   - no file on disk            → new file: write it.
//   - marker matches body        → pristine render of SOME vintage. If
//     it differs from the current render, it is byte-indistinguishable
//     from a deliberate edit (FRICTION fr-2c1c2328c7), so by DEFAULT the
//     write SKIPS it loudly (once-per-file notice). Overwriting requires
//     explicit opt-in: `--heal` (whole tree) or `--force` (this file).
//   - marker mismatches body     → hand-edited: the stomp guard refuses,
//     naming the file (per-run-scoped `--force` overwrites, `forge
//     disown` transfers ownership).
//   - no marker, file exists     → forge never certified these bytes at
//     a path it owns: write (matches the legacy untracked-path
//     behavior).
//
// ── What little persistent state remains under .forge/ ───────────────
//
//   - .forge/disowned.json — the one-way ownership door. Path + reason
//   - timestamp per `forge disown`. Generate skips these paths while
//     the file exists; deleting the file re-adopts it. Committed.
//   - .forge/hashes.json — the scoped fallback for the few Tier-1
//     output formats that cannot carry comments (JSON). path → body
//     hash of the last render. Deliberately minimal: this exception
//     must not regrow the global manifest. Committed.
//
// Scaffold ("yours") files carry NO marker and are user-owned from
// birth: forge writes each one exactly once, keyed on the file's own
// absence (WriteScaffoldIfMissing). Once the file exists forge NEVER
// overwrites it — no flag, no exception. To refresh one, delete it and
// regenerate. This is the single non-Tier-1 tier: there is no separate
// "scaffold reset" machinery (deleting the file IS the reset).
package checksums

import (
	"bytes"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"time"
)

// On-disk state files, project-relative.
const (
	// DisownedFile records one-way ownership transfers (`forge disown`).
	DisownedFile = ".forge/disowned.json"
	// HashesFile is the scoped fallback manifest for comment-incapable
	// Tier-1 outputs only (see package doc).
	HashesFile = ".forge/hashes.json"
	// LegacyChecksumFile is the dead global manifest. Only the one-time
	// migration (migrate.go) reads it; nothing writes it.
	LegacyChecksumFile = ".forge/checksums.json"
)

// ResetSkipWrite clears the written-this-run set. Called at the start of
// each pipeline run to avoid leaking state across forge invocations in
// tests or long-lived processes.
func ResetSkipWrite() {
	WrittenThisRun = map[string]bool{}
	Tier1TargetSet = map[string]bool{}
}

// Tier1TargetSet is the per-pipeline-run set of relative paths that the
// current run TARGETED as Tier-1 (regenerated-every-run) output — every
// path that flowed through a Tier-1 writer (WriteGeneratedFile /
// WriteGeneratedFileTier1 / writeUnstampable), recorded BEFORE the
// disown-skip early-return.
//
// Deliberately distinct from WrittenThisRun: a DISOWNED Tier-1 path is
// skipped (never written), so it is absent from WrittenThisRun — yet
// forge WOULD have regenerated it but for the disown, so it IS in
// Tier1TargetSet. That distinction is exactly what obsolete-disown
// retirement needs: a disown is still VALID iff its path is a current
// Tier-1 target (in this set); it is OBSOLETE (the path became a
// scaffold-once "yours" file, or forge no longer emits it at all) iff it
// is NOT in this set.
//
// Scaffold-once ("yours") writes do NOT record here — those paths are
// user-owned write-if-absent, never Tier-1 targets.
var Tier1TargetSet = map[string]bool{}

// markTier1Target records relPath as a Tier-1 emit target for this run.
// Called at the head of every Tier-1 writer, before any disown-skip, so
// the set reflects what forge WOULD regenerate independent of ownership
// transfers.
func markTier1Target(relPath string) { Tier1TargetSet[relPath] = true }

// WrittenThisRun is a per-pipeline-run set of relative paths that the
// current `forge generate` invocation has successfully written via the
// `WriteGeneratedFile*` family. The marker-driven stale-artifact sweep
// consults this set: a marker-bearing file NOT in it is a candidate for
// removal (forge certified the path but didn't re-emit it this run,
// e.g. because the service was renamed or removed).
var WrittenThisRun = map[string]bool{}

// MarkWrittenThisRun records that relPath was written during the
// current run. Exposed publicly so tests that bypass the
// WriteGeneratedFile* chokepoint can still simulate the post-emit set.
func MarkWrittenThisRun(relPath string) { WrittenThisRun[relPath] = true }

// sideRenderOnly is the per-run set of paths whose Tier-1 writes are
// redirected to `.forge/render/<relpath>` instead of the real file.
// Populated by `forge generate --explain-drift` (show what regeneration
// would change without touching the user's drifted file) and by the
// legacy-manifest migration's provenance rescue (compare the committed
// bytes against a fresh render before deciding pristine vs hand-edited).
var sideRenderOnly = map[string]bool{}

// AddSideRenderOnly marks relPath as side-render-only for the current
// run. Idempotent.
func AddSideRenderOnly(relPath string) { sideRenderOnly[relPath] = true }

// ResetPerRunState clears the per-pipeline-run tracking sets (the
// side-render redirects, the heal-notice machinery, the --heal opt-in
// (AutoHeal), and the per-run --force scope). Called at the start of
// each pipeline run so a long-lived process doesn't leak state across
// invocations.
func ResetPerRunState() {
	sideRenderOnly = map[string]bool{}
	healNoticed = map[string]bool{}
	pendingHeals = map[string]string{}
	AutoHeal = false
	forceScope = nil
}

// forceScope is the per-run set of relative paths `--force` is allowed
// to clobber. nil (the default) means UNSCOPED — force keeps its
// historical "overwrite any modified file" meaning, which is right for
// non-pipeline callers (`forge upgrade`, project creation) and for
// pipeline presets that deliberately skip the stomp guard.
//
// The generate pipeline installs a scope (SetForceScope) from inside
// the Tier-1 stomp guard: --force means "discard the edits the guard
// just reported", not "force-overwrite anything any emitter happens to
// touch this run". Journey fr-a04f8c0609: a user recovering from a
// Tier-1 trip with --force watched unrelated files get re-scaffolded
// "(your edits discarded)".
var forceScope map[string]bool

// SetForceScope installs the per-run --force scope: only the given
// relative paths may be force-overwritten. Passing an empty (or nil)
// slice installs an EMPTY scope — force becomes inert — which is
// distinct from never calling SetForceScope (unscoped legacy force).
// Cleared by ResetPerRunState.
func SetForceScope(relPaths []string) {
	forceScope = make(map[string]bool, len(relPaths))
	for _, p := range relPaths {
		forceScope[p] = true
	}
}

// forceApplies reports whether a force=true write may clobber relPath
// under the current scope. force=false is never an overwrite license.
func forceApplies(relPath string, force bool) bool {
	if !force {
		return false
	}
	if forceScope == nil {
		return true // unscoped legacy force
	}
	return forceScope[relPath]
}

// AutoHeal opts IN to overwriting on-disk content whose marker VERIFIES
// but whose body differs from the current render (a pristine render of
// an older vintage). It is OFF by default, and that default is the
// correctness fix for FRICTION cp-forge fr-2c1c2328c7.
//
// The hazard: a deliberate user revert (or hand-edit) to content forge
// once rendered is BYTE-INDISTINGUISHABLE from stale codegen — both
// produce a file whose embedded marker self-verifies (Pristine) but
// whose body is an older vintage. The old default healed (overwrote)
// these silently-then-loudly, which SILENTLY DESTROYED a real hand-edit
// in pkg/app/bootstrap.go: the edit happened to hash-equal a prior
// render, so generate treated the user's drift as stale codegen and
// reverted it. The notice fired AFTER the bytes were already gone.
//
// forge generate must never be silently destructive, so the default is
// now the NON-DESTRUCTIVE outcome: a pristine-but-stale file is treated
// as a possible hand-edit — the write SKIPS it and NoHealSkipFn fires
// once per file per run, naming the file and the remedies. Overwriting
// requires explicit intent: `forge generate --heal` (sets AutoHeal) to
// advance the whole tree to the current templates, or `forge generate
// --force` to discard a specific drifted file. Either way the user, not
// forge, decides to throw the bytes away.
//
// `forge upgrade` does not consult this var — it has its own diff-driven
// writer with its own --force.
var AutoHeal bool

// HealNoticeFn is invoked once per file per run when an EXPLICITLY
// requested heal (--heal / AutoHeal, or a scoped --force) has replaced
// on-disk content that was a PRISTINE OLDER forge render with the
// current template's output. Healing must never be silent: even when the
// user opted in, if the old vintage was actually a deliberate edit, this
// notice is the only trace that forge threw it away.
//
// Package var so the CLI can redirect the report; the default prints to
// stderr. Never nil it out — assign a no-op func in tests instead.
var HealNoticeFn = func(relPath string) {
	fmt.Fprintf(os.Stderr,
		"♻️  healed stale codegen: %s — on-disk content was a pristine prior forge render (not the latest); overwrote it with the current template (you opted in via --heal/--force). If that content was a deliberate edit, restore it, then move the edit to an extension point or `forge disown` the file.\n",
		relPath)
}

// NoHealSkipFn is invoked once per file per run when the default
// non-destructive behavior caused a write to SKIP a pristine-but-stale
// file. This is the DEFAULT outcome (AutoHeal off): the file's body is an
// older forge render than the current template, which is
// byte-indistinguishable from a deliberate user revert/edit, so forge
// refuses to silently overwrite it. Default prints to stderr.
var NoHealSkipFn = func(relPath string) {
	fmt.Fprintf(os.Stderr,
		"⏭️  %s matches a PRIOR forge render but not the current template — left untouched, because that is byte-indistinguishable from a deliberate edit and forge will not silently revert your work. To regenerate it from the current templates: `forge generate --heal` (advances every such file) or `forge generate --force` (this file only). To keep your version permanently: `forge disown %s`.\n",
		relPath, relPath)
}

// healNoticed is the per-run dedupe set for HealNoticeFn / NoHealSkipFn
// — multiple emitters may write the same path in one pipeline run; the
// user needs one notice per file, not one per write.
var healNoticed = map[string]bool{}

// noticeHealOnce fires NoHealSkipFn at most once per file per run for a
// non-destructive skip of a pristine-but-stale render (the default when
// neither AutoHeal nor this file's --force scope applies). Dedupes via
// healNoticed so multiple emitters writing the same path yield one notice.
func noticeHealOnce(relPath string) {
	if healNoticed[relPath] {
		return
	}
	healNoticed[relPath] = true
	if NoHealSkipFn != nil {
		NoHealSkipFn(relPath)
	}
}

// pendingHeals defers the heal notice until after post-write formatters
// (goimports) have run: path → body hash of the pristine on-disk
// content that the write replaced. If the FINAL on-disk body hash ends
// up equal to the replaced one, the "heal" was formatting-only noise
// (the emitter's pre-goimports output differed, the formatted result
// converged back) and no notice fires. FlushHealNotices resolves the
// set; non-pipeline callers (forge upgrade) flush immediately after
// their writes.
var pendingHeals = map[string]string{}

// FlushHealNotices emits the deferred heal notices for every pending
// path whose final on-disk body hash actually changed relative to the
// pristine content the run replaced. Clears the pending set.
func FlushHealNotices(root string) {
	for relPath, oldBody := range pendingHeals {
		onDisk, err := os.ReadFile(filepath.Join(root, relPath))
		if err != nil {
			continue
		}
		if BodyHash(onDisk) == oldBody {
			continue // formatting-only churn; nothing was destroyed
		}
		if healNoticed[relPath] {
			continue
		}
		healNoticed[relPath] = true
		if HealNoticeFn != nil {
			HealNoticeFn(relPath)
		}
	}
	pendingHeals = map[string]string{}
}

// DisownedEntry is the per-path record in .forge/disowned.json: the
// WHY of the one-way ownership transfer plus when it happened. The
// reason is design feedback — it's also recorded in
// .forge/friction.jsonl by the CLI layer.
type DisownedEntry struct {
	Reason     string `json:"reason,omitempty"`
	DisownedAt string `json:"disowned_at,omitempty"`
}

// FileChecksums is the project's persistent ownership state. The name
// survives from the manifest era (every emitter signature threads a
// *FileChecksums); the global per-file hash map does NOT — Tier-1
// pristineness lives inside the files themselves (stamp.go).
type FileChecksums struct {
	// ForgeVersion is the version of the binary performing the current
	// run. Carried for save-time stamping of the state files.
	ForgeVersion string `json:"forge_version,omitempty"`

	// Disowned maps project-relative paths to their one-way ownership
	// transfer records. Loaded from / saved to .forge/disowned.json.
	Disowned map[string]DisownedEntry `json:"-"`

	// Unstampable maps project-relative paths of comment-incapable
	// Tier-1 outputs (JSON, …) to the BodyHash of forge's last render.
	// Loaded from / saved to .forge/hashes.json. The ONLY paths allowed
	// here are ones Stampable() rejects — the writer enforces it.
	Unstampable map[string]string `json:"-"`
}

// IsDisowned reports whether relPath has been `forge disown`-ed.
func (cs *FileChecksums) IsDisowned(relPath string) bool {
	if cs == nil {
		return false
	}
	_, ok := cs.Disowned[relPath]
	return ok
}

// disownedJSON / hashesJSON are the wire shapes of the two state files.
type disownedJSON struct {
	ForgeVersion string                   `json:"forge_version,omitempty"`
	Files        map[string]DisownedEntry `json:"files"`
}

type hashesJSON struct {
	ForgeVersion string            `json:"forge_version,omitempty"`
	Files        map[string]string `json:"files"`
}

// Load reads the project ownership state (.forge/disowned.json +
// .forge/hashes.json). Missing files yield empty maps — a project with
// no disowns and no comment-incapable outputs has NO forge state files
// at all, by design.
func Load(root string) (*FileChecksums, error) {
	cs := &FileChecksums{
		Disowned:    map[string]DisownedEntry{},
		Unstampable: map[string]string{},
	}
	if data, err := os.ReadFile(filepath.Join(root, DisownedFile)); err == nil {
		var d disownedJSON
		if jerr := json.Unmarshal(data, &d); jerr != nil {
			return nil, fmt.Errorf("parse %s: %w", DisownedFile, jerr)
		}
		if d.Files != nil {
			cs.Disowned = d.Files
		}
	} else if !os.IsNotExist(err) {
		return nil, err
	}
	if data, err := os.ReadFile(filepath.Join(root, HashesFile)); err == nil {
		var h hashesJSON
		if jerr := json.Unmarshal(data, &h); jerr != nil {
			return nil, fmt.Errorf("parse %s: %w", HashesFile, jerr)
		}
		if h.Files != nil {
			cs.Unstampable = h.Files
		}
	} else if !os.IsNotExist(err) {
		return nil, err
	}
	return cs, nil
}

// Save persists the ownership state. Empty maps DELETE their state file
// — the steady state for most projects is no .forge state files at all,
// so regeneration produces zero bookkeeping diff (the manifest-era
// "22/69 commits were pure bookkeeping" failure mode).
func Save(root string, cs *FileChecksums) error {
	if cs == nil {
		return nil
	}
	if err := saveStateFile(root, DisownedFile, len(cs.Disowned), disownedJSON{ForgeVersion: cs.ForgeVersion, Files: cs.Disowned}); err != nil {
		return err
	}
	return saveStateFile(root, HashesFile, len(cs.Unstampable), hashesJSON{ForgeVersion: cs.ForgeVersion, Files: cs.Unstampable})
}

// saveStateFile writes one state file, or removes it when its map is
// empty.
func saveStateFile(root, relPath string, n int, v any) error {
	full := filepath.Join(root, relPath)
	if n == 0 {
		if err := os.Remove(full); err != nil && !os.IsNotExist(err) {
			return err
		}
		return nil
	}
	if err := os.MkdirAll(filepath.Dir(full), 0o755); err != nil {
		return err
	}
	data, err := json.MarshalIndent(v, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(full, append(data, '\n'), 0o644)
}

// Hash returns the sha256 hex digest of content.
func Hash(content []byte) string {
	h := sha256.Sum256(content)
	return hex.EncodeToString(h[:])
}

// WriteGeneratedFile writes a Tier-1 (forge-owned, regenerated every
// run) file through the certification chokepoint:
//
//   - .go renders are CANONICAL-FORMATTED first (goformat.go: gofmt +
//     goimports grouping, module path as local prefix) so the stamped
//     bytes are a fixed point of the formatter a user's tooling runs;
//   - the rendered content is STAMPED with its embedded forge:hash
//     marker (comment-incapable formats fall back to the scoped
//     .forge/hashes.json entry);
//   - existing on-disk content is classified by Verify: pristine
//     content regenerates (healing older vintages loudly), hand-edited
//     content is skipped unless force applies, unmarked content is
//     overwritten (forge owns the path; it never certified those bytes);
//   - disowned paths are never touched while the file exists.
//
// Returns true if the file was written. A nil cs is tolerated — the
// file is still written and stamped, but disowned/unstampable state
// can't be consulted or recorded.
//
// Historical note: this used to be the tier-agnostic legacy writer with
// WriteGeneratedFileTier1 layering a manifest tag on top. Every
// remaining caller emits regenerated-every-run output, so both names
// now share Tier-1 semantics.
func WriteGeneratedFile(root, relPath string, content []byte, cs *FileChecksums, force bool) (bool, error) {
	// Record the Tier-1 emit TARGET before any disown-skip below: forge
	// would regenerate this path this run, whether or not it's disowned.
	// The obsolete-disown retirement consults this set — a disowned path
	// absent from it is no longer Tier-1-owned (became scaffold-once or
	// dropped entirely) and the disown is dead weight.
	markTier1Target(relPath)

	// Disowned: user-owned — never overwrite, even with force=true
	// (--force discards current-run hand-edits to forge-owned files; it
	// does not undo a recorded ownership transfer). Exception —
	// re-adoption: if the file is GONE the user deleted it to hand it
	// back to forge. Fall through, re-emit, and clear the record.
	reAdopting := false
	if cs.IsDisowned(relPath) {
		if _, statErr := os.Stat(filepath.Join(root, relPath)); statErr == nil {
			return false, nil
		} else if !os.IsNotExist(statErr) {
			return false, statErr
		}
		reAdopting = true
	}

	// Canonical-format Go BEFORE stamping (see goformat.go): the embedded
	// hash must certify bytes that are a fixed point of the canonical
	// formatter (gofmt + goimports grouping with the module path as the
	// local prefix). Stamping a non-canonical render would let the first
	// formatter pass over the tree turn a pristine file into byte drift
	// that the stomp guard misreads as a hand-edit.
	content = canonicalizeGoForWrite(root, relPath, content)

	stamped, stampable := Stamp(relPath, content)
	if !stampable {
		return writeUnstampable(root, relPath, content, cs, force)
	}

	if sideRenderOnly[relPath] {
		// `--explain-drift` / migration-rescue redirect: park the fresh
		// (stamped) render for the post-pipeline comparison, leave the
		// user's on-disk content untouched.
		if err := WriteSideRenderNoBase(root, relPath, stamped); err != nil {
			return false, err
		}
		return false, nil
	}

	onDisk, readErr := os.ReadFile(filepath.Join(root, relPath))
	switch {
	case readErr == nil:
		switch Verify(onDisk) {
		case Pristine:
			oldBody := BodyHash(onDisk)
			if oldBody != BodyHash(stamped) {
				// A pristine render of some OLDER vintage. This is
				// byte-indistinguishable from a deliberate user revert
				// (FRICTION fr-2c1c2328c7), so the DEFAULT is to NOT
				// overwrite: skip and say so loudly via NoHealSkipFn.
				// Healing (overwrite) requires explicit opt-in — AutoHeal
				// (--heal) for the whole tree, or this file's --force scope.
				if !AutoHeal && !forceApplies(relPath, force) {
					noticeHealOnce(relPath)
					return false, nil
				}
				if _, pending := pendingHeals[relPath]; !pending {
					pendingHeals[relPath] = oldBody
				}
			}
		case Modified:
			// Byte drift is not always semantic drift: a formatter pass
			// (goimports regrouping imports, gofmt realigning whitespace)
			// rewrites bytes without touching meaning. Normalize-on-compare
			// before treating the mismatch as a hand-edit (goformat.go).
			embedded, _ := ExtractMarker(onDisk)
			canonBody, canonOK := canonicalGoBody(root, relPath, onDisk)
			switch {
			case canonOK && canonBody == BodyHash(stamped):
				// Formatter-equivalent to the CURRENT render: overwriting
				// loses nothing user-authored and heals both the formatting
				// and the stale stamp. Fall through to the write.
			case canonOK && canonBody == embedded && embedded != UnverifiedMarkerValue:
				// Formatter-equivalent to the certified OLDER render — the
				// clean-file analogue of Pristine-but-stale, so the same
				// non-destructive default applies: skip loudly unless the
				// user opted in via --heal or this file's --force scope.
				if !AutoHeal && !forceApplies(relPath, force) {
					noticeHealOnce(relPath)
					return false, nil
				}
				if _, pending := pendingHeals[relPath]; !pending {
					pendingHeals[relPath] = embedded
				}
			case !forceApplies(relPath, force):
				// Hand-edited after forge stamped it: the stomp guard's
				// territory. Skip unless this run's --force scope covers it.
				return false, nil
			}
		case NoMarker:
			// Forge never certified these bytes at a path it owns —
			// the legacy untracked-path behavior: write.
		}
	case !os.IsNotExist(readErr):
		return false, readErr
	}

	fullPath := filepath.Join(root, relPath)
	if err := os.MkdirAll(filepath.Dir(fullPath), 0o755); err != nil {
		return false, err
	}
	// Capture the pre-run bytes BEFORE the first write so a failed run can
	// be rolled back to a clean pre-regen tree (fr-40f7ec9bd9).
	recordPreWrite(root, relPath)
	if err := atomicWriteFile(fullPath, stamped, 0o644); err != nil {
		return false, err
	}
	WrittenThisRun[relPath] = true
	if reAdopting && cs != nil {
		delete(cs.Disowned, relPath)
	}
	return true, nil
}

// writeUnstampable is the Tier-1 write path for comment-incapable
// formats (JSON, …): pristineness is tracked in the scoped
// .forge/hashes.json instead of an embedded marker. Same outcomes as
// the stamped path: recorded-hash match → regenerate (loud heal when
// the content actually changes), mismatch → hand-edited (skip unless
// force), no record → write.
func writeUnstampable(root, relPath string, content []byte, cs *FileChecksums, force bool) (bool, error) {
	newBody := BodyHash(content)
	if sideRenderOnly[relPath] {
		if err := WriteSideRenderNoBase(root, relPath, content); err != nil {
			return false, err
		}
		return false, nil
	}
	onDisk, readErr := os.ReadFile(filepath.Join(root, relPath))
	if readErr != nil && !os.IsNotExist(readErr) {
		return false, readErr
	}
	if readErr == nil && cs != nil {
		recorded, tracked := cs.Unstampable[relPath]
		onDiskBody := BodyHash(onDisk)
		switch {
		case tracked && onDiskBody == recorded:
			// Pristine last render. When regeneration would actually
			// change it, the default is non-destructive: skip and say so
			// (same fr-2c1c2328c7 rationale as the stamped path).
			if onDiskBody != newBody {
				if !AutoHeal && !forceApplies(relPath, force) {
					noticeHealOnce(relPath)
					return false, nil
				}
				if _, pending := pendingHeals[relPath]; !pending {
					pendingHeals[relPath] = onDiskBody
				}
			}
		case tracked: // mismatch → hand-edited
			if !forceApplies(relPath, force) {
				return false, nil
			}
		}
	}
	fullPath := filepath.Join(root, relPath)
	if err := os.MkdirAll(filepath.Dir(fullPath), 0o755); err != nil {
		return false, err
	}
	recordPreWrite(root, relPath)
	if err := atomicWriteFile(fullPath, content, 0o644); err != nil {
		return false, err
	}
	if cs != nil {
		if cs.Unstampable == nil {
			cs.Unstampable = map[string]string{}
		}
		cs.Unstampable[relPath] = newBody
	}
	WrittenThisRun[relPath] = true
	return true, nil
}

// WriteGeneratedFileTier1 writes a Tier-1 (regenerated-every-run) file.
// Alias of WriteGeneratedFile — kept so call sites stay explicit about
// the tier they're emitting.
func WriteGeneratedFileTier1(root, relPath string, content []byte, cs *FileChecksums, force bool) (bool, error) {
	return WriteGeneratedFile(root, relPath, content, cs, force)
}

// atomicWriteFile writes content to path via a same-directory temp file
// followed by an atomic rename, so a reader (or a resumed run) never sees a
// half-written file. A plain os.WriteFile truncates-then-writes: if the
// process dies mid-write — the daemon disconnecting mid-`forge generate` —
// the target is left partial. That is exactly how gen/mcp/manifest.json ended
// up as truncated JSON that `forge mcp serve` and the MCP bridge choke on
// (fr F9). rename(2) within one directory is atomic on every filesystem forge
// targets, so the file is either the old bytes or the complete new bytes,
// never a prefix. The temp file is cleaned up on any error before the rename.
func atomicWriteFile(path string, content []byte, perm os.FileMode) error {
	dir := filepath.Dir(path)
	tmp, err := os.CreateTemp(dir, ".forge-tmp-*")
	if err != nil {
		return err
	}
	tmpName := tmp.Name()
	cleanup := true
	defer func() {
		if cleanup {
			_ = os.Remove(tmpName)
		}
	}()
	if _, err := tmp.Write(content); err != nil {
		_ = tmp.Close()
		return err
	}
	if err := tmp.Chmod(perm); err != nil {
		_ = tmp.Close()
		return err
	}
	if err := tmp.Close(); err != nil {
		return err
	}
	if err := os.Rename(tmpName, path); err != nil {
		return err
	}
	cleanup = false // renamed into place; nothing left to remove
	return nil
}

// WriteScaffoldIfMissing writes a scaffold ("yours") file only when the
// destination does not already exist. Scaffold content carries NO marker
// and is user-owned from birth: forge writes it once, then NEVER touches
// it again — no flag, no exception. To refresh, delete the file and
// regenerate (the write-if-absent gate re-emits the pristine scaffold).
//
// Returns true when the file was written (it was absent). A file already
// on disk — whether pristine, hand-edited, or fully rewritten — is left
// exactly as-is and returns (false, nil). Parent directories are created
// as needed.
func WriteScaffoldIfMissing(root, relPath string, content []byte) (bool, error) {
	fullPath := filepath.Join(root, relPath)
	if _, statErr := os.Stat(fullPath); statErr == nil {
		return false, nil // exists — forge never overwrites a scaffold
	} else if !os.IsNotExist(statErr) {
		return false, statErr
	}
	if err := os.MkdirAll(filepath.Dir(fullPath), 0o755); err != nil {
		return false, err
	}
	recordPreWrite(root, relPath)
	if err := atomicWriteFile(fullPath, content, 0o644); err != nil {
		return false, err
	}
	WrittenThisRun[relPath] = true
	return true, nil
}

// Tier1DriftEntry reports a single Tier-1 file whose on-disk content
// fails its own certification (embedded hash ≠ recomputed body hash) —
// positive evidence of a hand-edit. The slice returned by
// ScanTier1Drift is sorted for stable error messages.
type Tier1DriftEntry struct {
	Path         string
	RecordedHash string // the embedded (claimed) hash
	OnDiskHash   string // the recomputed body hash
	// Unverified marks the legacy-migration sentinel: the file's
	// provenance could not be established when the project migrated off
	// .forge/checksums.json. The remedies are the same (--force /
	// disown / restore), but the report wording differs.
	Unverified bool
}

// ScanTier1Drift walks the project for self-certifying files and
// returns every one whose verification fails (hand-edited), plus every
// scoped-fallback (comment-incapable) entry whose on-disk body hash
// mismatches the recorded render. Disowned paths are skipped — they're
// user-owned by recorded intent. Used as the pre-pipeline stomp guard.
func ScanTier1Drift(root string, cs *FileChecksums) []Tier1DriftEntry {
	var drift []Tier1DriftEntry
	for relPath, info := range ScanMarkers(root) {
		if cs.IsDisowned(relPath) {
			continue
		}
		if info.Status != Modified {
			continue
		}
		drift = append(drift, Tier1DriftEntry{
			Path:         relPath,
			RecordedHash: info.Embedded,
			OnDiskHash:   info.Body,
			Unverified:   info.Embedded == UnverifiedMarkerValue,
		})
	}
	if cs != nil {
		for relPath, recorded := range cs.Unstampable {
			if cs.IsDisowned(relPath) {
				continue
			}
			onDisk, err := os.ReadFile(filepath.Join(root, relPath))
			if err != nil {
				continue // gone or unreadable — not a stomp candidate
			}
			if b := BodyHash(onDisk); b != recorded {
				drift = append(drift, Tier1DriftEntry{Path: relPath, RecordedHash: recorded, OnDiskHash: b})
			}
		}
	}
	sortDrift(drift)
	return drift
}

// MarkerInfo is one ScanMarkers result: the verification status plus
// the embedded and recomputed hashes.
type MarkerInfo struct {
	Status   VerifyStatus
	Embedded string
	Body     string
}

// scanSkipDirs are directory basenames the marker scan never descends
// into: VCS state, forge's own scratch space, package managers, build
// output. `gen/` is NOT skipped — it's cheap (head-probe only) and
// skipping it would blind the scan to any future forge-certified
// output there.
var scanSkipDirs = map[string]bool{
	".git":         true,
	".forge":       true,
	".forge-pkg":   true,
	"node_modules": true,
	"vendor":       true,
	".next":        true,
	"dist":         true,
	"build":        true,
	// `.scratch/` is a gitignored throwaway workspace (smoke renders) and
	// `testdata/` holds analyzer fixtures that intentionally carry markers.
	// Neither is real project output; scanning them produces phantom
	// "orphan"/"modified" findings against forge's own repo.
	".scratch": true,
	"testdata": true,
}

// markerProbeBytes bounds the head-read used to detect a marker before
// committing to a full-file read. Stamp places markers within the
// banner block at the top of the file, so 4 KiB is generous.
const markerProbeBytes = 4096

// ScanMarkers walks root and returns every file carrying a forge:hash
// marker, keyed by slash-separated project-relative path. Only
// stampable formats are probed; probe reads are head-bounded so large
// generated trees (gen/, proto stubs) cost almost nothing.
func ScanMarkers(root string) map[string]MarkerInfo {
	out := map[string]MarkerInfo{}
	_ = filepath.Walk(root, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return nil
		}
		if info.IsDir() {
			if scanSkipDirs[info.Name()] {
				return filepath.SkipDir
			}
			return nil
		}
		if !info.Mode().IsRegular() {
			return nil
		}
		rel, relErr := filepath.Rel(root, path)
		if relErr != nil {
			return nil
		}
		rel = filepath.ToSlash(rel)
		if !Stampable(rel) {
			return nil
		}
		if !headContainsMarker(path) {
			return nil
		}
		content, readErr := os.ReadFile(path)
		if readErr != nil {
			return nil
		}
		embedded, found := ExtractMarker(content)
		if !found {
			return nil
		}
		mi := MarkerInfo{Embedded: embedded, Body: BodyHash(content)}
		switch {
		case embedded == mi.Body:
			mi.Status = Pristine
		case goFormatterEquivalent(root, rel, content, embedded):
			// Formatter-only drift on a .go file: the bytes re-hash to the
			// certified render after canonical formatting (goformat.go), so
			// a goimports/gofmt pass — not a hand — produced the mismatch.
			// The file is clean; the next successful Tier-1 write restores
			// canonical bytes and a fresh stamp. Non-Go formats keep
			// exact-byte semantics.
			mi.Status = Pristine
		default:
			mi.Status = Modified
		}
		out[rel] = mi
		return nil
	})
	return out
}

// headContainsMarker reports whether the first markerProbeBytes of the
// file contain the marker key.
func headContainsMarker(path string) bool {
	f, err := os.Open(path)
	if err != nil {
		return false
	}
	defer func() { _ = f.Close() }()
	buf := make([]byte, markerProbeBytes)
	n, _ := f.Read(buf)
	return n > 0 && bytes.Contains(buf[:n], []byte(markerKey))
}

// RestampWritten re-certifies every file written this run: post-write
// formatters (goimports) may have rewritten the bytes after the writer
// stamped them, which would otherwise leave the embedded hash stale and
// flag every formatted file as "hand-edited" on the next run. Also
// refreshes scoped-fallback entries for unstampable paths.
func RestampWritten(root string, cs *FileChecksums) {
	for relPath := range WrittenThisRun {
		full := filepath.Join(root, relPath)
		content, err := os.ReadFile(full)
		if err != nil {
			continue
		}
		if !Stampable(relPath) {
			if cs != nil {
				if _, tracked := cs.Unstampable[relPath]; tracked {
					cs.Unstampable[relPath] = BodyHash(content)
				}
			}
			continue
		}
		if _, found := ExtractMarker(content); !found {
			continue // scaffold ("yours") writes carry no marker
		}
		restamped, ok := Stamp(relPath, content)
		if !ok || bytes.Equal(restamped, content) {
			continue
		}
		_ = os.WriteFile(full, restamped, 0o644)
	}
}

// DisownPaths performs the one-way ownership transfer for each path:
// the embedded forge:hash marker is STRIPPED from the file (a
// user-owned file must not advertise forge certification), any scoped
// fallback entry is dropped, and the path is recorded in
// .forge/disowned.json with the user's reason. After this, no
// `WriteGeneratedFile*` call ever touches the path again (while the
// file exists). Re-adoption is by deletion: remove the file and run
// `forge generate`.
func (cs *FileChecksums) DisownPaths(root string, relPaths []string, reason string) error {
	if cs == nil {
		return nil
	}
	for _, p := range relPaths {
		full := filepath.Join(root, p)
		content, err := os.ReadFile(full)
		if err != nil {
			return err
		}
		if stripped := StripMarker(content); len(stripped) != len(content) {
			if werr := os.WriteFile(full, stripped, 0o644); werr != nil {
				return werr
			}
		}
		delete(cs.Unstampable, p)
		if cs.Disowned == nil {
			cs.Disowned = map[string]DisownedEntry{}
		}
		cs.Disowned[p] = DisownedEntry{Reason: reason, DisownedAt: nowRFC3339()}
		// Forge actively adjudicated this path this run — keep the
		// stale sweep away from it.
		WrittenThisRun[p] = true
	}
	return nil
}

// RetireNoticeFn is invoked once per auto-retired obsolete disown. A
// disown is OBSOLETE when forge no longer Tier-1-owns its path: the path
// became a scaffold-once "yours" file (write-if-absent, never
// overwritten), or forge stopped emitting it entirely. Such a disown is
// dead weight — it protects against an overwrite that can no longer
// happen — and misleads users into thinking `forge disown` is routine.
//
// Package var so the CLI can redirect/capture the report; the default
// prints to stderr. Never nil it out — assign a no-op in tests instead.
var RetireNoticeFn = func(relPath string) {
	fmt.Fprintf(os.Stderr,
		"♻️  retired obsolete disown: %s — forge no longer owns this as generated code (it's now scaffold-once/user-owned); the file stays yours, the disown was dropped.\n",
		relPath)
}

// RetireObsoleteDisowns drops disowns whose path is NO LONGER a current
// Tier-1 emit target, firing RetireNoticeFn for each. It must run AFTER
// every Tier-1 emitter (so Tier1TargetSet is fully populated) and BEFORE
// the state is saved.
//
// Conservatism — the retirement is one-directional and only ever drops a
// disown when forge is CERTAIN it no longer Tier-1-owns the path:
//
//   - a path IN Tier1TargetSet is one forge WOULD regenerate but for the
//     disown → the disown is doing its job → KEPT.
//   - a path NOT in Tier1TargetSet became scaffold-once ("yours") or is
//     no longer emitted → the disown can never prevent an overwrite →
//     RETIRED.
//
// The guard against false retirement: callers must only invoke this when
// the Tier-1 target set is TRUSTWORTHY for the disowned path's owning
// emitter — i.e. that emitter's pipeline step actually ran this run. A
// disowned path whose emitter was gated OFF this run (e.g. a
// frontend-only file under features.frontend=false) would be absent from
// the target set for a reason unrelated to tiering, and must NOT be
// retired. RetireObsoleteDisowns takes a `targetable` predicate: it only
// considers a disown for retirement when targetable(path) is true,
// meaning "an emitter that COULD own this path as Tier-1 ran this run".
// A nil predicate means "trust the target set for every path" (used by
// unit tests that drive the set directly).
//
// Returns the sorted list of retired paths.
func RetireObsoleteDisowns(cs *FileChecksums, targetable func(relPath string) bool) []string {
	if cs == nil || len(cs.Disowned) == 0 {
		return nil
	}
	var retired []string
	for path := range cs.Disowned {
		if Tier1TargetSet[path] {
			continue // still a live Tier-1 target — disown stays valid.
		}
		if targetable != nil && !targetable(path) {
			// The owning emitter didn't run this run; absence from the
			// target set is uninformative. Be conservative: keep it.
			continue
		}
		retired = append(retired, path)
	}
	if len(retired) == 0 {
		return nil
	}
	sortStrings(retired)
	for _, path := range retired {
		delete(cs.Disowned, path)
		if RetireNoticeFn != nil {
			RetireNoticeFn(path)
		}
	}
	return retired
}

// sortStrings sorts s ascending in place (insertion sort — the slices
// here are tiny: the disowned set of a project).
func sortStrings(s []string) {
	for i := 1; i < len(s); i++ {
		for j := i; j > 0 && s[j-1] > s[j]; j-- {
			s[j-1], s[j] = s[j], s[j-1]
		}
	}
}

// sortDrift sorts a slice of Tier1DriftEntry by Path, ascending.
func sortDrift(drift []Tier1DriftEntry) {
	for i := 1; i < len(drift); i++ {
		for j := i; j > 0 && drift[j-1].Path > drift[j].Path; j-- {
			drift[j-1], drift[j] = drift[j], drift[j-1]
		}
	}
}

// nowRFC3339 returns the current UTC time in RFC3339. Indirected
// through a package var so tests can pin a deterministic timestamp.
var nowRFC3339 = func() string {
	return time.Now().UTC().Format(time.RFC3339)
}
